sys_rest_message_fn.script:
(function executeRestMessage(input, response) {
    var selector = new BuildAgentSelector();
    var requirement = input.body.requirement || '';
    var options = input.body.options || {};

    var agents = selector.getActiveAgents();
    var taskType = selector.classifyTask(requirement);
    var estimatedTokens = selector.estimateTokens(requirement);

    var scoredAgents = agents.map(function(agent) {
        return {
            agent: agent,
            score: selector.scoreAgent(agent, {
                taskType: taskType,
                estimatedTokens: estimatedTokens,
                options: options
            })
        };
    });

    scoredAgents.sort(function(a, b) {
        return b.score - a.score;
    });

    response.setBody(JSON.stringify({ agents: scoredAgents }));
    response.setStatus(200);
})(input, response);
